class Solution {
public:
    int maxScoreSightseeingPair(vector<int>& values) {
        int maxScore = 0;
        int prevValue = values[0];
        for (int i = 1; i < values.size(); i++) {
            maxScore = max(maxScore, prevValue + values[i] + i - 1);
            prevValue = values[i];
        }
        return maxScore;
    }
};
